public  static ETGShippingAdviseController construct()
{
    return new ETGShippingAdviseController();
}

public static void main(Args    _args)
{
    ETGShippingAdviseController     shippingAdviseController;
    ETGShippingAdviseContract       shippingAdviseContract;
    SalesAgreementHeader            salesHeader;

    shippingAdviseController    =   ETGShippingAdviseController::construct();
    salesHeader                 =   _args.record() as SalesAgreementHeader;

    shippingAdviseController    =   new ETGShippingAdviseController(
                                    classStr (ETGShippingAdviseService),
                                    methodStr(ETGShippingAdviseService , generateReportByGER),
                                    SysOperationExecutionMode::Synchronous);
    shippingAdviseContract      =   shippingAdviseController.getDataContractObject();

    shippingAdviseContract.parmSalesAgreementId(salesHeader.SalesNumberSequence); // Setting the Value of agreement id

    shippingAdviseController.parmArgs(_args);
    shippingAdviseController.parmShowDialog(false);
    shippingAdviseController.startOperation();
}
